def purchase_within_budget(items, budget):
    item_details = []
    total = 0.0
    for i, item in enumerate(items):
        inc_price = item['price'] * 1.1 if item['taxable'] else item['price']
        total += inc_price
        item_details.append({
            'index': i,
            'name': item['name'],
            'inc_price': inc_price,
            'removed': False
        })

    if total <= budget:
        return [item['name'] for item in items]

    sort_key = lambda x: (-x['inc_price'], x['index'])
    sorted_details = sorted(item_details, key=sort_key)

    for details in sorted_details:
        if total <= budget:
            break
        total -= details['inc_price']
        details['removed'] = True

    remaining = [d['name'] for d in item_details if not d['removed']]
    return remaining

