def calcular_media_ponderada(avaliacoes):
    if not avaliacoes:
        return 0.0

    lista_copia = list(avaliacoes)

    if len(lista_copia) >= 3:
        menor = min(lista_copia, key=lambda x: x['nota'])
        lista_copia.remove(menor)

    soma_notas = 0.0
    soma_pesos = 0.0
    for av in lista_copia:
        soma_notas += av['nota'] * av['peso']
        soma_pesos += av['peso']

    if soma_pesos == 0.0:
        return 0.0

    return soma_notas / soma_pesos

