def compress_string(s):
    if not s:
        return ""
    compressed = []
    current_char = s[0]
    count = 0
    for char in s:
        if char == current_char:
            count += 1
        else:
            compressed.append(current_char + str(count))
            current_char = char
            count = 1
    compressed.append(current_char + str(count))
    compressed_str = "".join(compressed)
    return compressed_str if len(compressed_str) < len(s) else s

