from urllib.parse import unquote

def parse_query(qs):
    result = {}
    if not qs:
        return result
    for part in qs.split('&'):
        if not part:
            continue
        if '=' in part:
            key, val = part.split('=', 1)
        else:
            key, val = part, ''
        key = unquote(key)
        val = unquote(val)
        if key in result:
            if isinstance(result[key], list):
                result[key].append(val)
            else:
                result[key] = [result[key], val]
        else:
            result[key] = val
    return result

