def encode_rle(s: str) -> str:
    if not s:
        return ""
    encoding = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i - 1]:
            count += 1
        else:
            encoding.append(f"{count}{s[i-1]}")
            count = 1
    encoding.append(f"{count}{s[-1]}")
    return "".join(encoding)

