def resolve_dependencies(target, package_db, resolved=None, seen=None):
    if resolved is None:
        resolved = []
    if seen is None:
        seen = set()

    name, op, constraint_version = parse_constraint(target)

    # Check if this package name is in the circular dependency stack
    if name in seen:
        raise ValueError("Circular dependency detected")

    # Check if we have already resolved a version for this package
    resolved_version = None
    for item in resolved:
        r_name, r_op, r_version = parse_constraint(item)
        if r_name == name:
            resolved_version = r_version
            break

    if resolved_version is not None:
        # Check if the already resolved version satisfies the new constraint
        if matches_constraint(resolved_version, op, constraint_version):
            return resolved
        else:
            raise ValueError(f"Version conflict for {name}: {resolved_version} does not satisfy {target}")

    seen.add(name)

    best_version = find_best_version(name, op, constraint_version, package_db)
    if not best_version:
        raise ValueError(f"No matching version for {target}")

    deps = package_db[name][best_version].get("dependencies", [])
    for dep in deps:
        resolve_dependencies(dep, package_db, resolved, seen)

    resolved.append(f"{name}=={best_version}")
    seen.remove(name)
    return resolved
