class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end = True

    def find_matches(self, pattern: str) -> list:
        results = []

        def dfs(node, index, path):
            if index == len(pattern):
                if node.is_end:
                    results.append("".join(path))
                return

            char = pattern[index]
            if char == '.':
                for child_char, child_node in node.children.items():
                    path.append(child_char)
                    dfs(child_node, index + 1, path)
                    path.pop()
            else:
                if char in node.children:
                    path.append(char)
                    dfs(node.children[char], index + 1, path)
                    path.pop()

        dfs(self.root, 0, [])
        return sorted(results)
