from typing import Dict, List, Tuple

def shortest_path_with_fewest_edges(
    graph: Dict[str, List[Tuple[str, float]]], start: str, end: str
) -> Tuple[float, List[str]]:
    pq = [(0.0, 0, start, [start])]
    min_cost = {start: (0.0, 0)}

    while pq:
        cost, edges, u, path = heapq.heappop(pq)

        if u == end:
            return cost, path

        if (cost, edges) > min_cost[u]:
            continue

        for neighbor, weight in graph.get(u, []):
            new_cost = cost + weight
            new_edges = edges + 1
            if neighbor not in min_cost or (new_cost, new_edges) < min_cost[neighbor]:
                min_cost[neighbor] = (new_cost, new_edges)
                heapq.heappush(pq, (new_cost, new_edges, neighbor, path + [neighbor]))

    return float('inf'), []

