def schedule_tasks(tasks: dict, R_max: int) -> int:
    # Cycle detection
    visited = {}
    def has_cycle(node):
        visited[node] = 1
        for dep in tasks[node].get("dependencies", []):
            if dep not in tasks:
                return True
            if visited.get(dep, 0) == 1:
                return True
            if visited.get(dep, 0) == 0:
                if has_cycle(dep):
                    return True
        visited[node] = 2
        return False

    for task in tasks:
        if visited.get(task, 0) == 0:
            if has_cycle(task):
                return -1

    t = 0
    running = {}
    completed = set()
    remaining = set(tasks.keys())

    while remaining or running:
        # Reclaim resources of completed tasks
        for task_id, end_time in list(running.items()):
            if end_time <= t:
                completed.add(task_id)
                del running[task_id]

        # Find available tasks
        available = []
        for task_id in remaining:
            deps = tasks[task_id].get("dependencies", [])
            if all(dep in completed for dep in deps):
                available.append(task_id)

        # Sort available tasks by resource usage (descending), then ID (alphabetically)
        available.sort(key=lambda x: (-tasks[x]["resources"], x))

        # Start tasks if resources are available
        current_resources = sum(tasks[tid]["resources"] for tid in running)
        for task_id in available:
            req = tasks[task_id]["resources"]
            if current_resources + req <= R_max:
                running[task_id] = t + tasks[task_id]["duration"]
                remaining.remove(task_id)
                current_resources += req

        if running:
            t = min(running.values())
        else:
            if remaining:
                return -1

    return t

