        if user not in duracao_total:
            duracao_total[user] = 0.0

        if user in sessoes_ativas:
            tempo_desde_ultimo = (ts - ultimo_evento_usuario[user]).total_seconds() / 60.0
            if tempo_desde_ultimo > timeout_inatividade_minutos:
                duracao = (ultimo_evento_usuario[user] - sessoes_ativas[user]).total_seconds() / 60.0
                duracao_total[user] += duracao
                del sessoes_ativas[user]
                if tipo == 'login':
                    sessoes_ativas[user] = ts
            else:
                if tipo == 'logout':
                    duracao = (ts - sessoes_ativas[user]).total_seconds() / 60.0
                    duracao_total[user] += duracao
                    del sessoes_ativas[user]
        else:
            if tipo == 'login':
                sessoes_ativas[user] = ts

        ultimo_evento_usuario[user] = ts

    for user, inicio in sessoes_ativas.items():
        ultimo = ultimo_evento_usuario[user]
        if (timestamp_maximo - ultimo).total_seconds() / 60.0 > timeout_inatividade_minutos:
            duracao = (ultimo - inicio).total_seconds() / 60.0
        else:
            duracao = (timestamp_maximo - inicio).total_seconds() / 60.0
        duracao_total[user] += duracao

    return duracao_total

