class TTLCache:
    def __init__(self, capacity):
        self.capacity = capacity
        self.cache = {}  # key -> [value, expire_time, last_access_time]

    def get(self, key, current_time):
        if key not in self.cache:
            return None
        value, expire_time, last_access_time = self.cache[key]
        if current_time >= expire_time:
            del self.cache[key]
            return None
        self.cache[key][2] = current_time
        return value

    def set(self, key, value, ttl, current_time):
        # Remove expired entries safely
        expired_keys = [k for k, v in self.cache.items() if current_time >= v[1]]
        for k in expired_keys:
            del self.cache[k]

        if key in self.cache:
            self.cache[key][0] = value
            self.cache[key][1] = current_time + ttl
            self.cache[key][2] = current_time
        else:
            self.cache[key] = [value, current_time + ttl, current_time]

        if len(self.cache) > self.capacity:
            to_evict = min(
                self.cache.keys(),
                key=lambda k: (self.cache[k][1], self.cache[k][2])
            )
            del self.cache[to_evict]

