class TransactionalKVS:
    def __init__(self):
        self.stack = [{}]
        self.deleted_sentinel = object()

    def begin(self):
        self.stack.append({})

    def get(self, key):
        for tx in reversed(self.stack):
            if key in tx:
                if tx[key] is self.deleted_sentinel:
                    raise KeyError(key)
                return tx[key]
        raise KeyError(key)

    def set(self, key, value):
        self.stack[-1][key] = value

    def delete(self, key):
        try:
            self.get(key)
        except KeyError:
            raise KeyError(key)
        self.stack[-1][key] = self.deleted_sentinel

    def commit(self):
        if len(self.stack) <= 1:
            raise Exception("No active transaction")
        top = self.stack.pop()
        for k, v in top.items():
            if len(self.stack) == 1 and v is self.deleted_sentinel:
                if k in self.stack[-1]:
                    del self.stack[-1][k]
            else:
                self.stack[-1][k] = v

    def rollback(self):
        if len(self.stack) <= 1:
            raise Exception("No active transaction")
        self.stack.pop()

