        self.children = {}
        self.is_word = False

class WordDictionary:
    def __init__(self):
        self.root = TrieNode()

    def add_word(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_word = True

    def search(self, word: str) -> bool:
        return self._search_node(word, 0, self.root)

    def _search_node(self, word: str, index: int, node: TrieNode) -> bool:
        if index == len(word):
            return node.is_word

        char = word[index]
        if char == '.':
            for child in node.children.values():
                if self._search_node(word, index + 1, child):
                    return True
            return False
        else:
            if char not in node.children:
                return False
            return self._search_node(word, index + 1, node.children[char])
