def resumen_estadistico(numeros):
    if not numeros:
        return None
    n = len(numeros)
    suma = sum(numeros)
    media = round(suma / n, 2)
    ordenados = sorted(numeros)
    mitad = n // 2
    if n % 2 == 1:
        mediana = ordenados[mitad]
    else:
        mediana = round((ordenados[mitad - 1] + ordenados[mitad]) / 2, 2)
    frecuencias = {}
    for x in numeros:
        frecuencias[x] = frecuencias.get(x, 0) + 1
    max_frec = max(frecuencias.values())
    if max_frec == 1:
        moda = []
    else:
        moda = sorted([x for x, f in frecuencias.items() if f == max_frec])
    return {'suma': suma, 'media': media, 'mediana': mediana, 'moda': moda}

def select_optimal_intervals(intervals: list[dict]) -> list[str]:
    best_weight = -1
    best_count = float('inf')
    best_ids = []

    def overlap(i1, i2):
        return max(i1['start'], i2['start']) <= min(i1['end'], i2['end'])

    n = len(intervals)

    def backtrack(idx, current_subset):
        nonlocal best_weight, best_count, best_ids

        weight_sum = sum(inv['weight'] for inv in current_subset)
        count = len(current_subset)
        ids = sorted([inv['id'] for inv in current_subset])

        if weight_sum > best_weight:
            best_weight = weight_sum
            best_count = count
            best_ids = ids
        elif weight_sum == best_weight:
            if count < best_count:
                best_count = count
                best_ids = ids
            elif count == best_count:
                if ids < best_ids:
                    best_ids = ids

        for i in range(idx, n):
            candidate = intervals[i]
            possible = True
            for inv in current_subset:
                if overlap(inv, candidate) or inv['label'] == candidate['label']:
                    possible = False
                    break
            if possible:
                backtrack(i + 1, current_subset + [candidate])

    backtrack(0, [])
    return best_ids

