import heapq

def min_cost_path(grid: list[list[int]], K: int) -> int:
    R = len(grid)
    C = len(grid[0])

    dist = {}
    pq = [(0, 0, 0, 0)]  # (cost, r, c, k)
    dist[(0, 0, 0)] = 0

    while pq:
        cost, r, c, k = heapq.heappop(pq)

        if cost > dist.get((r, c, k), float('inf')):
            continue

        if r == R - 1 and c == C - 1:
            return cost

        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < R and 0 <= nc < C:
                val = grid[nr][nc]
                if val == 0:
                    next_cost = cost + 1
                    next_k = k
                else:
                    next_cost = cost + val
                    next_k = k + 1

                if next_k <= K:
                    if next_cost < dist.get((nr, nc, next_k), float('inf')):
                        dist[(nr, nc, next_k)] = next_cost
                        heapq.heappush(pq, (next_cost, nr, nc, next_k))

    ans = float('inf')
    for k in range(K + 1):
        ans = min(ans, dist.get((R-1, C-1, k), float('inf')))

    return ans if ans != float('inf') else -1

def validate_and_format_markup(text: str) -> str:
    bracket_positions = []
    i = 0
    while i < len(text):
        if text[i] == '[':
            bracket_positions.append(('open', i))
        elif text[i] == ']':
            bracket_positions.append(('close', i))
        i += 1

    if len(bracket_positions) % 2 != 0:
        raise ValueError("Mismatched brackets")
    for idx in range(0, len(bracket_positions), 2):
        if bracket_positions[idx][0] != 'open' or bracket_positions[idx+1][0] != 'close':
            raise ValueError("Stray or nested brackets")

    output = []
    last_idx = 0
    stack = []

    for idx in range(0, len(bracket_positions), 2):
        open_pos = bracket_positions[idx][1]
        close_pos = bracket_positions[idx+1][1]

        output.append(text[last_idx:open_pos])
        tag_content = text[open_pos+1:close_pos]

        if tag_content.startswith('/'):
            tag_name = tag_content[1:]
            if tag_name not in ('b', 'i', 'u', 'color'):
                raise ValueError(f"Invalid closing tag: {tag_name}")
            if not stack:
                raise ValueError("Closing tag without matching opening tag")
            expected_tag = stack.pop()
            if expected_tag != tag_name:
                raise ValueError(f"Mismatched closing tag")
            output.append(f"[/{tag_name}]")
        else:
            if tag_content == 'b':
                stack.append('b')
                output.append('[b]')
            elif tag_content == 'i':
                stack.append('i')
                output.append('[i]')
            elif tag_content == 'u':
                stack.append('u')
                output.append('[u]')
            elif tag_content.startswith('color='):
                parts = tag_content.split('=', 1)
                hex_val = parts[1]
                if len(hex_val) != 6 or not all(c in '0123456789abcdefABCDEF' for c in hex_val):
                    raise ValueError(f"Invalid hex color: {hex_val}")
                stack.append('color')
                output.append(f"[color={hex_val.upper()}]")
            else:
                raise ValueError(f"Invalid opening tag: {tag_content}")

        last_idx = close_pos + 1

    output.append(text[last_idx:])

    if stack:
        raise ValueError("Unclosed tags remaining")

    return "".join(output)

def parse_artifact_manifest(raw: str) -> dict:
    import re

    def valid_id(s: str) -> bool:
        if not s or s[0] == '-' or s[-1] == '-':
            return False
        if '--' in s:
            return False
        return bool(re.fullmatch(r'[a-z0-9-]+', s))

    def valid_version(s: str) -> tuple[bool, str]:
        parts = s.split('.')
        if len(parts) != 3:
            return False, ''
        norm_parts = []
        for p in parts:
            if not p.isdigit():
                return False, ''
            if len(p) > 1 and p[0] == '0':
                return False, ''
            n = int(p)
            if n > 999:
                return False, ''
            norm_parts.append(f'{n:03d}')
        return True, '.'.join(norm_parts)

    def valid_checksum(s: str) -> bool:
        return len(s) == 64 and all(c in '0123456789abcdef' for c in s)

    def valid_size(s: str) -> tuple[bool, int]:
        if not s or not s.isdigit():
            return False, 0
        if len(s) > 1 and s[0] == '0':
            return False, 0
        n = int(s)
        if n > 2**63 - 1:
            return False, 0
        return True, n

    artifacts = []
    errors = []
    if not raw or raw.strip() == '':
        return {"artifacts": artifacts, "errors": errors}

    nonempty = [line for line in raw.split('\n') if line.strip() != '']
    for idx, line in enumerate(nonempty, start=1):
        parts = line.split(':')
        if len(parts) != 4 or any(p == '' for p in parts):
            errors.append({"line": idx, "reason": "malformed_line"})
            continue
        aid, ver, chk, size_str = parts
        if not valid_id(aid):
            errors.append({"line": idx, "reason": "invalid_id"})
            continue
        ok_ver, norm_ver = valid_version(ver)
        if not ok_ver:
            errors.append({"line": idx, "reason": "invalid_version"})
            continue
        if not valid_checksum(chk):
            errors.append({"line": idx, "reason": "invalid_checksum"})
            continue
        ok_size, size_val = valid_size(size_str)
        if not ok_size:
            errors.append({"line": idx, "reason": "invalid_size"})
            continue
        artifacts.append({
            "id": aid,
            "version": ver,
            "checksum": chk,
            "size_bytes": size_val,
            "normalized_version": norm_ver,
        })

    return {"artifacts": artifacts, "errors": errors}

import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, num_replicas: int):
        self.num_replicas = num_replicas
        self.ring = []  # List of tuples (hash_val, physical_node)
        self.nodes = set()

    def _hash(self, key: str) -> int:
        return int(hashlib.sha256(key.encode('utf-8')).hexdigest(), 16)

    def add_node(self, node: str) -> None:
        if node in self.nodes:
            return
        self.nodes.add(node)
        for i in range(self.num_replicas):
            vnode_name = f"{node}-replica-{i}"
            h = self._hash(vnode_name)
            self.ring.append((h, node))
        self.ring.sort(key=lambda x: (x[0], x[1]))

    def remove_node(self, node: str) -> None:
        if node not in self.nodes:
            return
        self.nodes.remove(node)
        self.ring = [item for item in self.ring if item[1] != node]

    def get_node(self, key: str) -> str | None:
        if not self.ring:
            return None
        h = self._hash(key)
        idx = bisect.bisect_left(self.ring, (h, ""))
        if idx == len(self.ring):
            idx = 0
        return self.ring[idx][1]

from collections import deque

def caminho_minimo_gelo(grid: list[list[int]], start: list[int], end: list[int]) -> int:
    R = len(grid)
    C = len(grid[0])
    start_r, start_c = start[0], start[1]
    end_r, end_c = end[0], end[1]

    if start_r == end_r and start_c == end_c:
        return 0

    queue = deque([(start_r, start_c, 0)])
    visited = {(start_r, start_c)}

    while queue:
        r, c, dist = queue.popleft()

        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r, c
            while True:
                next_r = nr + dr
                next_c = nc + dc
                if 0 <= next_r < R and 0 <= next_c < C and grid[next_r][next_c] == 0:
                    nr = next_r
                    nc = next_c
                else:
                    break

            if nr == end_r and nc == end_c:
                return dist + 1

            if (nr, nc) not in visited:
                visited.add((nr, nc))
                queue.append((nr, nc, dist + 1))

    return -1

def solve_schedule(intervals: list[tuple[int, int]], max_overlap: int) -> list[tuple[int, int]]:
    from collections import defaultdict
    time_map = defaultdict(int)
    for start, end in intervals:
        time_map[start] += 1
        time_map[end] -= 1

    sorted_times = sorted(time_map.keys())
    result = []
    current_overlap = 0
    active_start = None

    for i in range(len(sorted_times) - 1):
        t_curr = sorted_times[i]
        t_next = sorted_times[i+1]
        current_overlap += time_map[t_curr]
        if current_overlap > max_overlap:
            if active_start is None:
                active_start = t_curr
        else:
            if active_start is not None:
                result.append((active_start, t_curr))
                active_start = None
    return result

def schedule_meetings(meetings, rooms):
    if rooms == 0 or not meetings:
        return 0
    meetings.sort(key=lambda x: x[1])
    import heapq
    end_times = []
    count = 0
    for start, end in meetings:
        if end_times and end_times[0] <= start:
            heapq.heappop(end_times)
            heapq.heappush(end_times, end)
            count += 1
        elif len(end_times) < rooms:
            heapq.heappush(end_times, end)
            count += 1
    return count

def find_stable_islands(matrix: list[list[int]], threshold: int) -> list[list[tuple[int, int]]]:
    if not matrix or not matrix[0]:
        return []

    rows = len(matrix)
    cols = len(matrix[0])
    visited = set()
    stable_islands = []

    for r in range(rows):
        for c in range(cols):
            if matrix[r][c] > threshold and (r, c) not in visited:
                queue = [(r, c)]
                visited.add((r, c))
                island = []
                idx = 0
                touches_boundary = False
                max_val = -float('inf')

                while idx < len(queue):
                    curr_r, curr_c = queue[idx]
                    idx += 1
                    island.append((curr_r, curr_c))

                    curr_val = matrix[curr_r][curr_c]
                    if curr_val > max_val:
                        max_val = curr_val

                    if curr_r == 0 or curr_r == rows - 1 or curr_c == 0 or curr_c == cols - 1:
                        touches_boundary = True

                    for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                        nr, nc = curr_r + dr, curr_c + dc
                        if 0 <= nr < rows and 0 <= nc < cols:
                            if matrix[nr][nc] > threshold and (nr, nc) not in visited:
                                visited.add((nr, nc))
                                queue.append((nr, nc))

                if not touches_boundary and max_val >= 2 * threshold:
                    island.sort(key=lambda x: (x[0], x[1]))
                    stable_islands.append(island)

    stable_islands.sort(key=lambda isl: (-len(isl), isl[0][0], isl[0][1]))
    return stable_islands

import copy

def resolve_config(base_config: dict, overrides: list[dict], blocked_keys: set[str]) -> dict:
    def is_blocked(path: str) -> bool:
        if path in blocked_keys:
            return True
        parts = path.split('.')
        for i in range(1, len(parts)):
            prefix = '.'.join(parts[:i])
            if prefix in blocked_keys:
                return True
        return False

    def clean_override(val, path: str):
        if not isinstance(val, dict):
            return val
        cleaned = {}
        for k, v in val.items():
            curr_path = f"{path}.{k}" if path else k
            if not is_blocked(curr_path):
                if isinstance(v, dict):
                    cleaned[k] = clean_override(v, curr_path)
                else:
                    cleaned[k] = copy.deepcopy(v)
        return cleaned

    def merge_recursive(target: dict, source: dict, path: str):
        for k, v in source.items():
            curr_path = f"{path}.{k}" if path else k
            if is_blocked(curr_path):
                continue
            if k in target:
                if isinstance(target[k], dict) and isinstance(v, dict):
                    merge_recursive(target[k], v, curr_path)
                else:
                    target[k] = clean_override(v, curr_path)
            else:
                target[k] = clean_override(v, curr_path)

    result = copy.deepcopy(base_config)
    for override in overrides:
        merge_recursive(result, override, "")
    return result

def bounded_running_median(stream, lower, upper):
    """Yield the running floor median of stream values strictly between lower and upper.

    Maintains two heaps: `small` is a max-heap of the lower half of accepted values,
    `large` is a min-heap of the upper half. Invariant: len(small) == len(large) or
    len(small) == len(large) + 1, and every value in small <= every value in large.
    The median is the top of small.
    """
    import heapq
    small = []  # max-heap via negation
    large = []  # min-heap

    for x in stream:
        if x <= lower or x >= upper:
            yield None if not small else -small[0]
            continue

        # Insert x into the appropriate heap.
        if not small or x <= -small[0]:
            heapq.heappush(small, -x)
        else:
            heapq.heappush(large, x)

        # Rebalance to keep invariant: small has same size or one more than large.
        if len(small) > len(large) + 1:
            heapq.heappush(large, -heapq.heappop(small))
        elif len(large) > len(small):
            heapq.heappush(small, -heapq.heappop(large))

        if not small:
            yield None
        else:
            yield -small[0]

def min_edit_cost(s1: str, s2: str, allowed_swaps: list[tuple[str, str]], swap_cost: int, replace_cost: int) -> int:
    m, n = len(s1), len(s2)
    swaps_set = set()
    for u, v in allowed_swaps:
        swaps_set.add((u, v))
        swaps_set.add((v, u))

    dp = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(m + 1):
        dp[i][0] = i * 3
    for j in range(n + 1):
        dp[0][j] = j * 3

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            cost_del = dp[i-1][j] + 3
            cost_ins = dp[i][j-1] + 3
            cost_rep = dp[i-1][j-1] + (0 if s1[i-1] == s2[j-1] else replace_cost)

            min_val = min(cost_del, cost_ins, cost_rep)

            if i > 1 and j > 1:
                if s1[i-1] == s2[j-2] and s1[i-2] == s2[j-1]:
                    if (s1[i-1], s1[i-2]) in swaps_set:
                        cost_swap = dp[i-2][j-2] + swap_cost
                        if cost_swap < min_val:
                            min_val = cost_swap
            dp[i][j] = min_val

    return dp[m][n]

def analisar_logs_acesso(logs: list[str], limite_tentativas: int, janela_tempo: int) -> list[str]:
    from collections import defaultdict
    ip_failures = defaultdict(list)

    for log in logs:
        parts = log.split(';')
        if len(parts) != 4:
            continue
        timestamp_str, ip, status, user = parts
        try:
            timestamp = int(timestamp_str)
        except ValueError:
            continue
        if status == 'FALHA':
            ip_failures[ip].append(timestamp)

    suspicious_ips = []
    for ip, times in ip_failures.items():
        times.sort()
        n = len(times)
        if n < limite_tentativas:
            continue

        is_suspicious = False
        left = 0
        for right in range(n):
            while times[right] - times[left] > janela_tempo:
                left += 1
            if right - left + 1 >= limite_tentativas:
                is_suspicious = True
                break
        if is_suspicious:
            suspicious_ips.append(ip)

    return sorted(suspicious_ips)

def encode_rle_bounded(data: str, max_chunk_len: int) -> list[tuple[str, int]]:
    if not data:
        return []
    result = []
    current_char = data[0]
    current_count = 0
    for char in data:
        if char == current_char:
            current_count += 1
            if current_count == max_chunk_len:
                result.append((current_char, current_count))
                current_count = 0
        else:
            if current_count > 0:
                result.append((current_char, current_count))
            current_char = char
            current_count = 1
    if current_count > 0:
        result.append((current_char, current_count))
    return result

def schedule_observations(observations, horizon_minutes, min_gap_minutes):
    # Filter out observations that exceed the horizon and keep original indices.
    filtered = [(start, end, priority, idx)
                for idx, (start, end, priority) in enumerate(observations)
                if end <= horizon_minutes]
    # Sort by end time, breaking ties by start time, then by original index.
    filtered.sort(key=lambda x: (x[1], x[0], x[3]))
    n = len(filtered)
    if n == 0:
        return (0, [])

    # ends[i] is the end time of the i-th observation in sorted order.
    ends = [filtered[i][1] for i in range(n)]

    # dp[i] = best (priority, indices_tuple) achievable using observations 0..i
    # We store indices as a tuple for easy comparison/lexicographic minimality.
    dp = [None] * n

    def better(a, b):
        # Returns True if a is strictly better than b.
        if b is None:
            return True
        if a[0] != b[0]:
            return a[0] > b[0]
        return a[1] < b[1]

    for i in range(n):
        start, end, priority, idx = filtered[i]
        # Option 1: skip observation i.
        best = dp[i - 1] if i > 0 else (0, ())
        # Option 2: take observation i; find latest compatible observation j.
        # Compatibility: ends[j] + min_gap_minutes <= start.
        lo, hi = 0, i
        while lo < hi:
            mid = (lo + hi) // 2
            if ends[mid] + min_gap_minutes <= start:
                lo = mid + 1
            else:
                hi = mid
        j = lo - 1
        if j >= 0:
            prev = dp[j]
            cand = (prev[0] + priority, prev[1] + (idx,))
        else:
            cand = (priority, (idx,))
        if better(cand, best):
            best = cand
        dp[i] = best

    max_priority, selected = dp[-1]
    return (max_priority, list(selected))

def wrap_text(text: str, max_width: int) -> list[str]:
    words = [w for w in text.split(' ') if w]
    if not words:
        return []
    res = []
    curr_line = []
    curr_len = 0
    for word in words:
        if len(word) > max_width:
            if curr_line:
                res.append(" ".join(curr_line))
                curr_line = []
                curr_len = 0
            temp = word
            while len(temp) > max_width:
                res.append(temp[:max_width])
                temp = temp[max_width:]
            if temp:
                curr_line = [temp]
                curr_len = len(temp)
        else:
            space_needed = 1 if curr_line else 0
            if curr_len + space_needed + len(word) <= max_width:
                curr_line.append(word)
                curr_len += space_needed + len(word)
            else:
                res.append(" ".join(curr_line))
                curr_line = [word]
                curr_len = len(word)
    if curr_line:
        res.append(" ".join(curr_line))
    return res

def parse_duration(text: str) -> int:
    UNIT_SECONDS = {
        's': 1, 'sec': 1, 'secs': 1, 'second': 1, 'seconds': 1,
        'm': 60, 'min': 60, 'mins': 60, 'minute': 60, 'minutes': 60,
        'h': 3600, 'hr': 3600, 'hrs': 3600, 'hour': 3600, 'hours': 3600,
        'd': 86400, 'day': 86400, 'days': 86400,
        'w': 604800, 'week': 604800, 'weeks': 604800,
    }
    MAX_SECONDS = 2**31 - 1

    text = text.strip()
    if not text:
        return 0

    total = 0
    for component in text.split():
        # Split into numeric prefix and unit suffix.
        idx = 0
        while idx < len(component) and component[idx].isdigit():
            idx += 1
        if idx == 0 or idx == len(component):
            raise ValueError(f"Malformed component: {component!r}")

        number_part = component[:idx]
        unit_part = component[idx:].lower()

        # Reject floats, signs, and empty parts.
        if number_part.startswith('+') or number_part.startswith('-'):
            raise ValueError(f"Negative or signed duration: {component!r}")
        if not number_part.isdigit():
            raise ValueError(f"Non-integer duration: {component!r}")

        if unit_part not in UNIT_SECONDS:
            raise ValueError(f"Unknown unit: {unit_part!r}")

        value = int(number_part)
        seconds = value * UNIT_SECONDS[unit_part]
        total += seconds
        if total > MAX_SECONDS:
            raise OverflowError("Total duration exceeds maximum allowed seconds")

    return total

def convert_base(num_str: str, base_from: int, base_to: int) -> str:
    if not (2 <= base_from <= 36) or not (2 <= base_to <= 36):
        raise ValueError("Bases must be between 2 and 36")
    digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"
    num_str = num_str.upper()
    val = 0
    for char in num_str:
        digit_val = digits.find(char)
        if digit_val == -1 or digit_val >= base_from:
            raise ValueError(f"Invalid character {char} for base {base_from}")
        val = val * base_from + digit_val
    if val == 0:
        return "0"
    res = []
    while val > 0:
        res.append(digits[val % base_to])
        val //= base_to
    return "".join(reversed(res))

def agrupar_anagramas(palavras: list[str]) -> list[list[str]]:
    def normalizar(s: str) -> str:
        s = s.lower()
        substituicoes = {
            'á': 'a', 'à': 'a', 'â': 'a', 'ã': 'a', 'ä': 'a',
            'é': 'e', 'è': 'e', 'ê': 'e', 'ë': 'e',
            'í': 'i', 'ì': 'i', 'î': 'i', 'ï': 'i',
            'ó': 'o', 'ò': 'o', 'ô': 'o', 'õ': 'o', 'ö': 'o',
            'ú': 'u', 'ù': 'u', 'û': 'u', 'ü': 'u',
            'ç': 'c'
        }
        res = []
        for char in s:
            res.append(substituicoes.get(char, char))
        return "".join(sorted(res))

    grupos = {}
    ordem = []
    for palavra in palavras:
        chave = normalizar(palavra)
        if chave not in grupos:
            grupos[chave] = []
            ordem.append(chave)
        grupos[chave].append(palavra)

    return [grupos[chave] for chave in ordem]

def resumen_texto_seguro(texto, max_caracteres, palabras_prohibidas):
    PUNTUACION = '.,;:!?()[]{}"\'-_'  # incluye comillas simple y doble

    def limpiar(palabra):
        return ''.join(c for c in palabra if c not in PUNTUACION).lower()

    def buscar_prohibidas(texto_completo):
        encontradas = []
        for prohibida in palabras_prohibidas:
            for token in texto_completo.split():
                if limpiar(token) == prohibida.lower() and prohibida not in encontradas:
                    encontradas.append(prohibida)
        return encontradas

    if not texto or max_caracteres <= 0:
        return {
            "resumen": "",
            "palabras_encontradas": [],
            "es_valido": False,
            "longitud_final": 0,
        }

    if max_caracteres >= len(texto):
        resumen = texto
    else:
        corte = max_caracteres
        # Buscar el último espacio antes o en corte
        while corte > 0 and texto[corte] != ' ':
            corte -= 1
        if corte == 0:
            # La primera palabra es más larga que max_caracteres; tomarla completa
            corte = len(texto)
            for i, ch in enumerate(texto):
                if ch == ' ':
                    corte = i
                    break
        resumen = texto[:corte]

    # Quitar espacios al inicio y final por seguridad
    resumen = resumen.strip()

    palabras_encontradas = buscar_prohibidas(texto)

    prohibidas_en_resumen = []
    for prohibida in palabras_prohibidas:
        for token in resumen.split():
            if limpiar(token) == prohibida.lower() and prohibida not in prohibidas_en_resumen:
                prohibidas_en_resumen.append(prohibida)

    es_valido = (
        bool(resumen)
        and not resumen.startswith(' ')
        and not resumen.endswith(' ')
        and not prohibidas_en_resumen
    )

    return {
        "resumen": resumen,
        "palabras_encontradas": palabras_encontradas,
        "es_valido": es_valido,
        "longitud_final": len(resumen),
    }

def are_brackets_balanced(expr: str) -> bool:
    cleaned = [c for c in expr if c in "()[]{}?"]
    memo = {}
    def search(index: int, stack: tuple) -> bool:
        state = (index, stack)
        if state in memo:
            return memo[state]
        if index == len(cleaned):
            res = (len(stack) == 0)
            memo[state] = res
            return res
        char = cleaned[index]
        if char in "([{":
            res = search(index + 1, stack + (char,))
            memo[state] = res
            return res
        elif char in ")]}":
            if not stack:
                memo[state] = False
                return False
            matching = {')': '(', ']': '[', '}': '{'}
            if stack[-1] != matching[char]:
                memo[state] = False
                return False
            res = search(index + 1, stack[:-1])
            memo[state] = res
            return res
        else:
            for opening in "([{":
                if search(index + 1, stack + (opening,)):
                    memo[state] = True
                    return True
            if stack:
                if search(index + 1, stack[:-1]):
                    memo[state] = True
                    return True
            memo[state] = False
            return False
    return search(0, ())

def merge_labeled_intervals(intervals: list[tuple[int, int, str]]) -> list[tuple[int, int, list[str]]]:
    if not intervals:
        return []
    points = set()
    for start, end, _ in intervals:
        points.add(start)
        points.add(end)
    sorted_points = sorted(list(points))
    result = []
    for i in range(len(sorted_points) - 1):
        s, e = sorted_points[i], sorted_points[i+1]
        active_labels = []
        for start, end, label in intervals:
            if start <= s and e <= end:
                active_labels.append(label)
        if active_labels:
            result.append((s, e, sorted(active_labels)))
    if not result:
        return []
    merged = []
    curr_start, curr_end, curr_labels = result[0]
    for next_start, next_end, next_labels in result[1:]:
        if next_labels == curr_labels and next_start == curr_end:
            curr_end = next_end
        else:
            merged.append((curr_start, curr_end, curr_labels))
            curr_start, curr_end, curr_labels = next_start, next_end, next_labels
    merged.append((curr_start, curr_end, curr_labels))
    return merged

def rotate_matrix_layers(matrix: list[list[int]], k: int) -> list[list[int]]:
    if not matrix or not matrix[0]:
        return matrix
    m = len(matrix)
    n = len(matrix[0])
    num_layers = min(m, n) // 2
    res = [row[:] for row in matrix]
    for layer in range(num_layers):
        coords = []
        for col in range(layer, n - layer):
            coords.append((layer, col))
        for row in range(layer + 1, m - layer):
            coords.append((row, n - 1 - layer))
        for col in range(n - 2 - layer, layer - 1, -1):
            coords.append((m - 1 - layer, col))
        for row in range(m - 2 - layer, layer, -1):
            coords.append((row, layer))
        if not coords:
            continue
        values = [matrix[r][c] for r, c in coords]
        num_elements = len(coords)
        shift = k % num_elements
        rotated_values = values[shift:] + values[:shift]
        for idx, (r, c) in enumerate(coords):
            res[r][c] = rotated_values[idx]
    return res

def resolve_dependencies(dependencies: dict[str, list[str]]) -> list[str]:
    all_nodes = set(dependencies.keys())
    for deps in dependencies.values():
        all_nodes.update(deps)
    adj = {node: [] for node in all_nodes}
    in_degree = {node: 0 for node in all_nodes}
    for u, deps in dependencies.items():
        for v in deps:
            adj[v].append(u)
            in_degree[u] += 1
    queue = [node for node in all_nodes if in_degree[node] == 0]
    queue.sort()
    result = []
    while queue:
        queue.sort()
        curr = queue.pop(0)
        result.append(curr)
        for neighbor in adj[curr]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)
    if len(result) < len(all_nodes):
        raise ValueError("Circular dependency detected")
    return result

def parse_duration(text: str) -> int:
    import re
    if not text or not text.strip():
        raise ValueError("empty duration")
    pattern = re.compile(r"^\s*(\d+)\s*([smhdw])\s*$", re.IGNORECASE)
    multipliers = {"s": 1, "m": 60, "h": 3600, "d": 86400, "w": 604800}
    total = 0
    for raw in text.split(","):
        raw = raw.strip()
        if not raw:
            raise ValueError("empty component")
        m = pattern.match(raw)
        if not m:
            raise ValueError(f"invalid component: {raw!r}")
        value = int(m.group(1))
        unit = m.group(2).lower()
        total += value * multipliers[unit]
    return total

def avaliar_expressao(expressao: str, variaveis: dict[str, int]) -> int:
    import re
    expressao = expressao.replace(" ", "")
    if not re.match(r'^[a-zA-Z0-9+\-*/()]+$', expressao):
        raise ValueError("Caracteres invalidos na expressao")
    tokens = []
    i = 0
    n = len(expressao)
    while i < n:
        if expressao[i].isdigit():
            val = ""
            while i < n and expressao[i].isdigit():
                val += expressao[i]
                i += 1
            tokens.append(val)
        elif expressao[i].isalpha():
            name = ""
            while i < n and expressao[i].isalpha():
                name += expressao[i]
                i += 1
            if name not in variaveis:
                raise ValueError(f"Variavel nao declarada: {name}")
            tokens.append(str(variaveis[name]))
        else:
            tokens.append(expressao[i])
            i += 1
    def precedence(op):
        if op in ('+', '-'): return 1
        if op in ('*', '/'): return 2
        return 0
    def apply_op(ops, values):
        if len(values) < 2 or not ops:
            raise ValueError("Expressao invalida")
        val2 = values.pop()
        val1 = values.pop()
        op = ops.pop()
        if op == '+': values.append(val1 + val2)
        elif op == '-': values.append(val1 - val2)
        elif op == '*': values.append(val1 * val2)
        elif op == '/':
            if val2 == 0:
                raise ValueError("Divisao por zero")
            values.append(val1 // val2)
    values = []
    ops = []
    i = 0
    while i < len(tokens):
        token = tokens[i]
        if token.isdigit() or (token[0] == '-' and len(token) > 1):
            values.append(int(token))
        elif token == '(':
            ops.append(token)
        elif token == ')':
            while ops and ops[-1] != '(':
                apply_op(ops, values)
            if not ops or ops[-1] != '(':
                raise ValueError("Parenteses invalidos")
            ops.pop()
        elif token in ('+', '-', '*', '/'):
            if token == '-' and (i == 0 or tokens[i-1] in ('+', '-', '*', '/', '(')):
                values.append(0)
            while ops and precedence(ops[-1]) >= precedence(token):
                apply_op(ops, values)
            ops.append(token)
        else:
            raise ValueError(f"Token desconhecido: {token}")
        i += 1
    while ops:
        if ops[-1] == '(':
            raise ValueError("Parenteses invalidos")
        apply_op(ops, values)
    if len(values) != 1:
        raise ValueError("Expressao invalida")
    return values[0]

