import statistics
import math
from typing import List, Dict, Any, Optional

def resumen_estadistico_seguro(
    datos: List[Any],
    opciones: Dict[str, Any] = None
) -> Optional[Dict[str, Any]]:
    """Calcula media, mediana, desviación estándar y moda de una lista de números.

    Args:
        datos: Lista de números reales (puede contener None o NaN).
        opciones: Diccionario con opciones. 'ignorar_nulos' (bool) determina
            si se descartan None/NaN o se lanza ValueError.

    Returns:
        Diccionario con 'media', 'mediana', 'desviacion' y 'moda', o None si
        datos está vacía.

    Raises:
        ValueError: Si hay None o NaN y 'ignorar_nulos' no es True.
    """
    if opciones is None:
        opciones = {}
    ignorar_nulos = bool(opciones.get('ignorar_nulos', False))

    if not datos:
        return None

    limpios = []
    for x in datos:
        if x is None or (isinstance(x, float) and math.isnan(x)):
            if not ignorar_nulos:
                raise ValueError("Lista contiene valores nulos no permitidos")
        else:
            limpios.append(x)

    if not limpios:
        return None

    media = statistics.mean(limpios)
    mediana = statistics.median(limpios)
    desviacion = statistics.stdev(limpios) if len(limpios) > 1 else 0.0

    try:
        moda = statistics.multimode(limpios)
    except AttributeError:
        # Fallback para versiones anteriores de Python
        frecuencias = {}
        for v in limpios:
            frecuencias[v] = frecuencias.get(v, 0) + 1
        max_freq = max(frecuencias.values())
        moda = sorted([v for v, f in frecuencias.items() if f == max_freq])

    return {
        'media': media,
        'mediana': mediana,
        'desviacion': desviacion,
        'moda': sorted(moda),
    }
