def schedule_tasks(tasks: list[dict], setup_matrix: list[list[int]]) -> list[str]:
    from itertools import permutations
    best_reward = -1
    best_seq = []
    n = len(tasks)
    for k in range(n + 1):
        for perm in permutations(tasks, k):
            current_time = 0
            current_reward = 0
            possible = True
            prev_type = None
            seq_ids = []
            for t in perm:
                if prev_type is None:
                    setup = 0
                else:
                    setup = setup_matrix[prev_type][t['type']]
                finish_time = current_time + setup + t['processing_time']
                if finish_time > t['deadline']:
                    possible = False
                    break
                current_time = finish_time
                current_reward += t['reward']
                prev_type = t['type']
                seq_ids.append(t['id'])
            if possible:
                if current_reward > best_reward:
                    best_reward = current_reward
                    best_seq = seq_ids
                elif current_reward == best_reward:
                    if not best_seq or seq_ids < best_seq:
                        best_seq = seq_ids
    return best_seq

def schedule_interviews(candidates, slots, constraints):
    unavailable = constraints.get("unavailable", {})
    required_before = constraints.get("required_before", [])
    pair_separation = constraints.get("pair_separation", [])
    slot_index = {s: i for i, s in enumerate(slots)}
    n = len(candidates)

    def valid(assignment):
        for cand, slot in assignment.items():
            if slot in unavailable.get(cand, []):
                return False
        for a, b in required_before:
            if a in assignment and b in assignment:
                if slot_index[assignment[a]] >= slot_index[assignment[b]]:
                    return False
        for a, b, k in pair_separation:
            if a in assignment and b in assignment:
                if abs(slot_index[assignment[a]] - slot_index[assignment[b]]) <= k:
                    return False
        return True

    def backtrack(idx, used, assignment):
        if idx == n:
            return dict(assignment)
        cand = candidates[idx]
        for slot in slots:
            if slot in used:
                continue
            assignment[cand] = slot
            if not valid(assignment):
                del assignment[cand]
                continue
            used.add(slot)
            result = backtrack(idx + 1, used, assignment)
            used.remove(slot)
            del assignment[cand]
            if result is not None:
                return result
        return None

    return backtrack(0, set(), {})

def find_longest_chain(words: list[str], matrix: list[list[int]], threshold: int) -> list[str]:
    def is_edit_distance_one(w1: str, w2: str) -> bool:
        len1, len2 = len(w1), len(w2)
        if abs(len1 - len2) > 1: return False
        if len1 == len2:
            return sum(1 for c1, c2 in zip(w1, w2) if c1 != c2) == 1
        elif len1 < len2:
            i = j = diffs = 0
            while i < len1 and j < len2:
                if w1[i] != w2[j]:
                    diffs += 1
                    j += 1
                    if diffs > 1: return False
                else:
                    i += 1; j += 1
            return True
        else:
            return is_edit_distance_one(w2, w1)

    n = len(words)
    adj = {i: [] for i in range(n)}
    for i in range(n):
        for j in range(n):
            if i != j and is_edit_distance_one(words[i], words[j]) and matrix[i][j] <= threshold:
                adj[i].append((j, matrix[i][j]))
    best_path = []
    best_cost = float('inf')
    def dfs(curr, path, cost):
        nonlocal best_path, best_cost
        if len(path) > len(best_path):
            best_path = list(path)
            best_cost = cost
        elif len(path) == len(best_path):
            path_words = [words[idx] for idx in path]
            best_words = [words[idx] for idx in best_path]
            if cost < best_cost:
                best_path = list(path)
                best_cost = cost
            elif cost == best_cost and path_words < best_words:
                best_path = list(path)
                best_cost = cost
        for neighbor, weight in adj[curr]:
            if neighbor not in path:
                path.append(neighbor)
                dfs(neighbor, path, cost + weight)
                path.pop()
    for start in range(n):
        dfs(start, [start], 0)
    return [words[idx] for idx in best_path]

def bounded_median_of_sliding_windows(values, window_size):
    """Return the lower-median of each sliding window of length window_size in values.

    Args:
        values: A list of integers.
        window_size: A positive integer specifying the window length.

    Returns:
        A list of medians, one for each contiguous window of length window_size.
        If window_size > len(values) or values is empty, returns an empty list.
    """
    import heapq

    if not values or window_size > len(values):
        return []

    max_heap = []  # stores the smaller half as negated values
    min_heap = []  # stores the larger half
    delayed = {}  # counts of elements scheduled for lazy deletion
    k = window_size
    half_k = k // 2  # size of max_heap; min_heap has k - half_k elements

    def prune(heap):
        while heap:
            num = -heap[0] if heap is max_heap else heap[0]
            if delayed.get(num, 0):
                heapq.heappop(heap)
                delayed[num] -= 1
                if delayed[num] == 0:
                    del delayed[num]
            else:
                break

    def make_balance():
        # max_heap may have at most one more element than min_heap
        if len(max_heap) > half_k:
            moved = -heapq.heappop(max_heap)
            prune(max_heap)
            heapq.heappush(min_heap, moved)
        elif len(max_heap) < half_k and min_heap:
            moved = heapq.heappop(min_heap)
            prune(min_heap)
            heapq.heappush(max_heap, -moved)

    def add(num):
        if not max_heap or num <= -max_heap[0]:
            heapq.heappush(max_heap, -num)
        else:
            heapq.heappush(min_heap, num)
        make_balance()

    def remove(num):
        delayed[num] = delayed.get(num, 0) + 1
        if num <= -max_heap[0]:
            # logically remove from max_heap
            if num == -max_heap[0]:
                prune(max_heap)
        else:
            if min_heap and num == min_heap[0]:
                prune(min_heap)
        make_balance()

    # initialize first window
    for i in range(k):
        add(values[i])

    result = [-max_heap[0]]

    for i in range(k, len(values)):
        add(values[i])
        remove(values[i - k])
        prune(max_heap)
        prune(min_heap)
        make_balance()
        result.append(-max_heap[0])

    return result

def simplify_debts(transactions: list[tuple[str, str, int]]) -> list[tuple[str, str, int]]:
    from collections import defaultdict
    balances = defaultdict(int)
    for u, v, amt in transactions:
        balances[u] -= amt
        balances[v] += amt
    people = sorted([p for p, b in balances.items() if b != 0])
    if not people: return []
    n = len(people)
    initial_balances = [balances[p] for p in people]
    best_tx = None
    min_tx_count = float('inf')
    min_tx_sum = float('inf')
    def solve(idx, current_balances, current_txs):
        nonlocal best_tx, min_tx_count, min_tx_sum
        if len(current_txs) > min_tx_count: return
        while idx < n and current_balances[idx] == 0:
            idx += 1
        if idx == n:
            if all(b == 0 for b in current_balances):
                tx_count = len(current_txs)
                tx_sum = sum(t[2] for t in current_txs)
                sorted_txs = sorted(current_txs, key=lambda x: (x[0], x[1]))
                if tx_count < min_tx_count:
                    min_tx_count = tx_count
                    min_tx_sum = tx_sum
                    best_tx = sorted_txs
                elif tx_count == min_tx_count:
                    if tx_sum < min_tx_sum:
                        min_tx_sum = tx_sum
                        best_tx = sorted_txs
                    elif tx_sum == min_tx_sum:
                        if best_tx is None or sorted_txs < best_tx:
                            best_tx = sorted_txs
            return
        val = current_balances[idx]
        for j in range(idx + 1, n):
            if current_balances[j] * val < 0:
                next_balances = list(current_balances)
                next_balances[idx] = 0
                next_balances[j] += val
                if val < 0:
                    tx = (people[idx], people[j], -val)
                else:
                    tx = (people[j], people[idx], val)
                solve(idx + 1, next_balances, current_txs + [tx])
    solve(0, initial_balances, [])
    return best_tx if best_tx is not None else []

def parse_iso8601_duration(dur: str) -> dict:
    """Parse a strict ISO 8601 duration into a normalized integer dictionary.

    Format: P[n]Y[n]M[n]DT[n]H[n]M[n]S
    - n is a non-negative integer for all fields except seconds, which may have
      up to 3 fractional digits.
    - Fields are optional but must appear in the fixed order Y M D H M S.
    - No weeks, no signs, no empty components.
    """
    if not dur or dur[0] != 'P':
        raise ValueError("duration must start with P")

    # Split into date and time parts at the literal T.
    if 'T' in dur:
        date_part, time_part = dur.split('T', 1)
    else:
        date_part = dur
        time_part = ""

    # date_part must start with P and contain only Y/M/D designators.
    if not date_part.startswith('P'):
        raise ValueError("invalid duration")
    date_body = date_part[1:]

    # time_part must contain only H/M/S designators and cannot be empty if T present.
    if time_part == "" and dur.endswith('T'):
        raise ValueError("empty time part")

    def parse_segment(body: str, designators: str, allow_decimal: str | None) -> dict:
        """Parse a segment body given allowed designators in fixed order.

        Returns a dict mapping designator -> integer value (or milliseconds for
        the decimal-allowed designator).
        """
        result = {d: 0 for d in designators}
        i = 0
        last_designator_index = -1
        while i < len(body):
            # Read numeric token.
            j = i
            saw_dot = False
            while j < len(body):
                ch = body[j]
                if ch == '.':
                    if saw_dot or allow_decimal is None:
                        raise ValueError("invalid decimal")
                    # Decimal only allowed in the final designator segment.
                    if body[j - 1] not in '0123456789':
                        raise ValueError("decimal must follow digits")
                    saw_dot = True
                    j += 1
                elif ch.isdigit():
                    j += 1
                else:
                    break
            if j == i:
                raise ValueError("missing number")
            num_str = body[i:j]

            # Read designator.
            if j >= len(body):
                raise ValueError("missing designator")
            des = body[j]
            if des not in designators:
                raise ValueError(f"unexpected designator {des}")
            des_idx = designators.index(des)
            if des_idx <= last_designator_index:
                raise ValueError("designators out of order or duplicated")
            last_designator_index = des_idx

            if des == allow_decimal:
                if '.' in num_str:
                    int_part, frac_part = num_str.split('.', 1)
                    frac_part = (frac_part + '000')[:3]  # truncate to 3 digits
                    value = int(int_part) * 1000 + int(frac_part)
                else:
                    value = int(num_str) * 1000
            else:
                if '.' in num_str:
                    raise ValueError("decimal only allowed for seconds")
                value = int(num_str)

            result[des] = value
            i = j + 1

        return result

    date_designators = "YMD"
    time_designators = "HMS"
    date_values = parse_segment(date_body, date_designators, None)
    time_values = parse_segment(time_part, time_designators, 'S')

    return {
        "years": date_values['Y'],
        "months": date_values['M'],
        "days": date_values['D'],
        "hours": time_values['H'],
        "minutes": time_values['M'],
        "milliseconds": time_values['S'],
    }


