def matrix_path_sum(grid: list[list[int]], k: int) -> int:
    if not grid or not grid[0]: return -1
    m, n = len(grid), len(grid[0])
    memo = {}
    def dfs(r, c, collected):
        state = (r, c, collected)
        if state in memo: return memo[state]
        new_collected = tuple(sorted(set(collected + (grid[r][c],))))
        if len(new_collected) > k: return -float('inf')
        if r == m - 1 and c == n - 1:
            return grid[r][c] if len(new_collected) == k else -float('inf')
        res = -float('inf')
        if r + 1 < m:
            res = max(res, grid[r][c] + dfs(r + 1, c, new_collected))
        if c + 1 < n:
            res = max(res, grid[r][c] + dfs(r, c + 1, new_collected))
        memo[state] = res
        return res
    result = dfs(0, 0, ())
    return result if result != -float('inf') else -1

def schedule_observation_windows(satellites, requests, horizon_start, horizon_end):
    # Preprocess downlinks: keep only intervals at least 60s long and within horizon
    sat_downlinks = {}
    for sat in satellites:
        valid = []
        for ds, de in sat['downlink_times']:
            if de - ds >= 60.0 and de > ds:
                valid.append((ds, de))
        valid.sort()
        sat_downlinks[sat['id']] = valid

    # State per satellite: list of (start, end) imaging intervals, and downlinked-through time
    # We track memory as a list of (imaging_end, size) chunks not yet downlinked, ordered by imaging_end.
    sat_state = {}
    for sat in satellites:
        sat_state[sat['id']] = {
            'intervals': [],
            'undownlinked': [],  # list of (imaging_end, size)
            'last_downlink_end': None,  # time of last downlink that cleared memory
        }

    def can_downlink_by(sat_id, imaging_end, deadline):
        # Find earliest downlink interval starting at or after imaging_end and ending by deadline
        for ds, de in sat_downlinks[sat_id]:
            if ds >= imaging_end and de <= deadline and de - ds >= 60.0:
                return True, de
        return False, None

    def fits_horizon_and_overlap(sat, start, end):
        if start < horizon_start or end > horizon_end:
            return False
        for a, b in sat_state[sat['id']]['intervals']:
            if not (end <= a or start >= b):
                return False
        return True

    def memory_after_downlinks(sat_id, imaging_end):
        # Memory accumulated from accepted requests whose imaging_end <= imaging_end and not yet downlinked
        # A downlink clears all undownlinked data with imaging_end <= downlink_end (since downlink must occur at or after imaging end)
        # We simulate by tracking last_downlink_end: any chunk with imaging_end <= last_downlink_end is cleared.
        state = sat_state[sat_id]
        total = 0.0
        for chunk_end, size in state['undownlinked']:
            if state['last_downlink_end'] is None or chunk_end > state['last_downlink_end']:
                total += size
        return total

    def is_feasible(req, sat):
        if not (sat['lat_range'][0] <= req['lat'] <= sat['lat_range'][1]):
            return False
        duration_sec = req['duration_min'] * 60.0
        # start must be in [earliest, latest] and end within horizon
        earliest_start = max(req['earliest'], horizon_start)
        latest_start = min(req['latest'], horizon_end - duration_sec)
        if earliest_start > latest_start:
            return False
        # Try candidate start times: earliest_start and latest_start, and any boundary that makes downlink work
        # Since constraints are monotonic, checking earliest_start is sufficient for feasibility if a downlink exists.
        # However, downlink deadline depends on imaging_end, so later start may miss deadline while earlier works.
        # We check earliest_start; if feasible there, request is feasible for this satellite.
        start = earliest_start
        end = start + duration_sec
        if not fits_horizon_and_overlap(sat, start, end):
            return False
        # Check memory capacity
        current_mem = memory_after_downlinks(sat['id'], end)
        if current_mem + req['size_gb'] > sat['memory_gb']:
            return False
        # Check downlink requirement
        if req['required_downlink_within_min'] is not None:
            deadline = end + req['required_downlink_within_min'] * 60.0
            ok, _ = can_downlink_by(sat['id'], end, deadline)
            if not ok:
                return False
        return True, start, end

    scheduled = []
    remaining = list(requests)

    while remaining:
        best = None
        for req in remaining:
            for sat in satellites:
                feasible = is_feasible(req, sat)
                if not feasible:
                    continue
                _, start, end = feasible
                candidate = (-req['priority'], start, sat['id'], req['id'], sat, req, end)
                if best is None or candidate < best[:4]:
                    best = candidate
        if best is None:
            break
        _, start, sat_id, req_id, sat, req, end = best

        # Add observation
        sat_state[sat_id]['intervals'].append((start, end))
        sat_state[sat_id]['intervals'].sort()
        sat_state[sat_id]['undownlinked'].append((end, req['size_gb']))
        sat_state[sat_id]['undownlinked'].sort()

        # Apply any downlinks that are now eligible and clear memory
        # A downlink clears all undownlinked chunks with imaging_end <= downlink_end, provided downlink starts >= imaging_end.
        # Since all chunks have imaging_end <= downlink_end by eligibility, we can clear all undownlinked data up to downlink_end.
        for ds, de in sat_downlinks[sat_id]:
            if ds >= end:
                # This downlink can clear all current undownlinked data (and any future, but future not known yet)
                # Only clear chunks with chunk_end <= de
                new_undownlinked = []
                for chunk_end, size in sat_state[sat_id]['undownlinked']:
                    if chunk_end > de:
                        new_undownlinked.append((chunk_end, size))
                if len(new_undownlinked) < len(sat_state[sat_id]['undownlinked']):
                    sat_state[sat_id]['undownlinked'] = new_undownlinked
                    sat_state[sat_id]['last_downlink_end'] = de

        scheduled.append({
            'request_id': req_id,
            'satellite_id': sat_id,
            'start': start,
            'end': end,
        })
        remaining = [r for r in remaining if r['id'] != req_id]

    return scheduled

def calcular_menor_caminho_com_pedagio(n: int, arestas: list[tuple[int, int, int, int]], origem: int, destino: int, limite_pedagio: int) -> list[int]:
    import heapq
    from collections import defaultdict
    adj = defaultdict(list)
    for u, v, w, t in arestas:
        adj[u].append((v, w, t))
    pq = [(0, 0, origem, [origem])]
    visited = {}
    while pq:
        dist, toll, u, path = heapq.heappop(pq)
        if u == destino: return path
        if visited.get((u, toll), float('inf')) <= dist: continue
        visited[(u, toll)] = dist
        for v, w, t in adj[u]:
            nt = toll + t
            if nt <= limite_pedagio:
                heapq.heappush(pq, (dist + w, nt, v, path + [v]))
    return []

def resumen_estadistico_seguro(datos, opciones=None):
    if not datos:
        return None
    for x in datos:
        if not isinstance(x, (int, float)):
            raise ValueError("Todos los elementos deben ser numéricos")
    redondeo = None
    if opciones is not None:
        if "redondeo" in opciones:
            redondeo = opciones["redondeo"]
            if not isinstance(redondeo, int) or redondeo < 0 or redondeo > 10:
                raise ValueError("redondeo debe estar entre 0 y 10")
    n = len(datos)
    media = sum(datos) / n
    ordenados = sorted(datos)
    if n % 2 == 1:
        mediana = float(ordenados[n // 2])
    else:
        mediana = (ordenados[n // 2 - 1] + ordenados[n // 2]) / 2.0
    frecuencias = {}
    for x in datos:
        frecuencias[x] = frecuencias.get(x, 0) + 1
    max_freq = max(frecuencias.values())
    if max_freq == 1:
        moda = []
    else:
        moda = sorted([k for k, v in frecuencias.items() if v == max_freq])
    rango = max(datos) - min(datos)
    if redondeo is not None:
        media = round(media, redondeo)
        mediana = round(mediana, redondeo)
        rango = round(rango, redondeo)
    return {"media": media, "mediana": mediana, "moda": moda, "rango": rango}

def solve_cryptarithm(equation: str) -> dict[str, int]:
    import re
    from itertools import permutations
    letters = sorted(list(set(re.findall(r'[A-Z]', equation))))
    if len(letters) > 10: return {}
    words = re.findall(r'[A-Z]+', equation)
    leading_letters = set(w[0] for w in words if len(w) > 1)
    lhs, rhs = equation.split('==')
    lhs, rhs = lhs.strip(), rhs.strip()
    for perm in permutations(range(10), len(letters)):
        mapping = dict(zip(letters, perm))
        if any(mapping[char] == 0 for char in leading_letters): continue
        def eval_part(expr):
            temp = expr
            for char, val in mapping.items():
                temp = temp.replace(char, str(val))
            return eval(temp)
        try:
            if eval_part(lhs) == eval_part(rhs): return mapping
        except Exception:
            continue
    return {}

def max_profit_job_scheduling(jobs: list[dict]) -> int:
    job_map = {job['id']: job for job in jobs}
    best_profit = 0
    n = len(jobs)
    def is_valid(selected_ids):
        selected_set = set(selected_ids)
        for j_id in selected_ids:
            job = job_map[j_id]
            for dep_id in job['dependencies']:
                if dep_id not in selected_set: return False
                if job_map[dep_id]['end'] > job['start']: return False
        sorted_jobs = sorted([job_map[j_id] for j_id in selected_ids], key=lambda x: x['start'])
        for i in range(len(sorted_jobs) - 1):
            if sorted_jobs[i]['end'] > sorted_jobs[i+1]['start']: return False
        return True
    job_ids = list(job_map.keys())
    def dfs(idx, current_selection):
        nonlocal best_profit
        if idx == n:
            if is_valid(current_selection):
                profit = sum(job_map[j_id]['profit'] for j_id in current_selection)
                if profit > best_profit: best_profit = profit
            return
        dfs(idx + 1, current_selection + [job_ids[idx]])
        dfs(idx + 1, current_selection)
    dfs(0, [])
    return best_profit

def agrupar_mensagens(mensagens: list[dict], janela_tempo: int) -> list[list[str]]:
    from collections import defaultdict
    user_msgs = defaultdict(list)
    for msg in mensagens:
        user_msgs[msg['usuario']].append(msg)
    sessions = []
    for user, msgs in user_msgs.items():
        sorted_msgs = sorted(msgs, key=lambda x: (x['timestamp'], x['id']))
        if not sorted_msgs: continue
        current_session = [sorted_msgs[0]]
        for msg in sorted_msgs[1:]:
            if msg['timestamp'] - current_session[-1]['timestamp'] <= janela_tempo:
                current_session.append(msg)
            else:
                sessions.append(current_session)
                current_session = [msg]
        sessions.append(current_session)
    sessions.sort(key=lambda s: (s[0]['timestamp'], s[0]['id']))
    return [[msg['id'] for msg in s] for s in sessions]

